// SystemServiceHandler is an implementation of the gastrolog.v1.SystemService service.
type SystemServiceHandler interface {
	// GetConfig returns the current configuration.
	GetSystem(context.Context, *connect.Request[v1.GetSystemRequest]) (*connect.Response[v1.GetSystemResponse], error)
	// ListIngesters returns all registered ingesters.
	ListIngesters(context.Context, *connect.Request[v1.ListIngestersRequest]) (*connect.Response[v1.ListIngestersResponse], error)
	// GetIngesterStatus returns status for a specific ingester.
	GetIngesterStatus(context.Context, *connect.Request[v1.GetIngesterStatusRequest]) (*connect.Response[v1.GetIngesterStatusResponse], error)
	// PutFilter creates or updates a filter.
	PutFilter(context.Context, *connect.Request[v1.PutFilterRequest]) (*connect.Response[v1.PutFilterResponse], error)
	// DeleteFilter removes a filter.
	DeleteFilter(context.Context, *connect.Request[v1.DeleteFilterRequest]) (*connect.Response[v1.DeleteFilterResponse], error)
	// PutRotationPolicy creates or updates a rotation policy.
	PutRotationPolicy(context.Context, *connect.Request[v1.PutRotationPolicyRequest]) (*connect.Response[v1.PutRotationPolicyResponse], error)
	// DeleteRotationPolicy removes a rotation policy.
	DeleteRotationPolicy(context.Context, *connect.Request[v1.DeleteRotationPolicyRequest]) (*connect.Response[v1.DeleteRotationPolicyResponse], error)
	// PutRetentionPolicy creates or updates a retention policy.
	PutRetentionPolicy(context.Context, *connect.Request[v1.PutRetentionPolicyRequest]) (*connect.Response[v1.PutRetentionPolicyResponse], error)
	// DeleteRetentionPolicy removes a retention policy.
	DeleteRetentionPolicy(context.Context, *connect.Request[v1.DeleteRetentionPolicyRequest]) (*connect.Response[v1.DeleteRetentionPolicyResponse], error)
	// PutVault creates or updates a vault.
	PutVault(context.Context, *connect.Request[v1.PutVaultRequest]) (*connect.Response[v1.PutVaultResponse], error)
	// DeleteVault removes a vault (must be empty).
	DeleteVault(context.Context, *connect.Request[v1.DeleteVaultRequest]) (*connect.Response[v1.DeleteVaultResponse], error)
	// PutIngester creates or updates an ingester.
	PutIngester(context.Context, *connect.Request[v1.PutIngesterRequest]) (*connect.Response[v1.PutIngesterResponse], error)
	// DeleteIngester removes an ingester.
	DeleteIngester(context.Context, *connect.Request[v1.DeleteIngesterRequest]) (*connect.Response[v1.DeleteIngesterResponse], error)
	// GetSettings returns system settings (auth, query, scheduler, TLS, lookup).
	GetSettings(context.Context, *connect.Request[v1.GetSettingsRequest]) (*connect.Response[v1.GetSettingsResponse], error)
	// PutServiceSettings updates auth, query, scheduler, TLS, and cluster settings.
	// Only fields explicitly set in the request are merged.
	PutServiceSettings(context.Context, *connect.Request[v1.PutServiceSettingsRequest]) (*connect.Response[v1.PutServiceSettingsResponse], error)
	// PutLookupSettings updates HTTP/JSON/YAML/MMDB/CSV/static lookup tables.
	PutLookupSettings(context.Context, *connect.Request[v1.PutLookupSettingsRequest]) (*connect.Response[v1.PutLookupSettingsResponse], error)
	// PutMaxMindSettings updates MaxMind auto-download configuration.
	PutMaxMindSettings(context.Context, *connect.Request[v1.PutMaxMindSettingsRequest]) (*connect.Response[v1.PutMaxMindSettingsResponse], error)
	// PutSetupSettings updates setup-wizard dismissal state.
	PutSetupSettings(context.Context, *connect.Request[v1.PutSetupSettingsRequest]) (*connect.Response[v1.PutSetupSettingsResponse], error)
	// RegenerateJwtSecret generates a new random JWT signing secret, replacing the
	// existing one. All active sessions are immediately invalidated cluster-wide.
	RegenerateJwtSecret(context.Context, *connect.Request[v1.RegenerateJwtSecretRequest]) (*connect.Response[v1.RegenerateJwtSecretResponse], error)
	// GetPreferences returns the current user's preferences.
	GetPreferences(context.Context, *connect.Request[v1.GetPreferencesRequest]) (*connect.Response[v1.GetPreferencesResponse], error)
	// PutPreferences updates the current user's preferences.
	PutPreferences(context.Context, *connect.Request[v1.PutPreferencesRequest]) (*connect.Response[v1.PutPreferencesResponse], error)
	// GetSavedQueries returns the current user's saved queries.
	GetSavedQueries(context.Context, *connect.Request[v1.GetSavedQueriesRequest]) (*connect.Response[v1.GetSavedQueriesResponse], error)
	// PutSavedQuery creates or updates a saved query by name.
	PutSavedQuery(context.Context, *connect.Request[v1.PutSavedQueryRequest]) (*connect.Response[v1.PutSavedQueryResponse], error)
	// DeleteSavedQuery removes a saved query by name.
	DeleteSavedQuery(context.Context, *connect.Request[v1.DeleteSavedQueryRequest]) (*connect.Response[v1.DeleteSavedQueryResponse], error)
	// ListCertificates returns all certificates.
	ListCertificates(context.Context, *connect.Request[v1.ListCertificatesRequest]) (*connect.Response[v1.ListCertificatesResponse], error)
	// GetCertificate returns a certificate by ID (includes PEM content).
	GetCertificate(context.Context, *connect.Request[v1.GetCertificateRequest]) (*connect.Response[v1.GetCertificateResponse], error)
	// PutCertificate creates or updates a certificate.
	PutCertificate(context.Context, *connect.Request[v1.PutCertificateRequest]) (*connect.Response[v1.PutCertificateResponse], error)
	// DeleteCertificate removes a certificate.
	DeleteCertificate(context.Context, *connect.Request[v1.DeleteCertificateRequest]) (*connect.Response[v1.DeleteCertificateResponse], error)
	// PauseVault pauses ingestion for a vault.
	PauseVault(context.Context, *connect.Request[v1.PauseVaultRequest]) (*connect.Response[v1.PauseVaultResponse], error)
	// ResumeVault resumes ingestion for a vault.
	ResumeVault(context.Context, *connect.Request[v1.ResumeVaultRequest]) (*connect.Response[v1.ResumeVaultResponse], error)
	// TestIngester tests connectivity for an ingester configuration without saving it.
	TestIngester(context.Context, *connect.Request[v1.TestIngesterRequest]) (*connect.Response[v1.TestIngesterResponse], error)
	// GetIngesterDefaults returns default parameter values for each ingester type.
	GetIngesterDefaults(context.Context, *connect.Request[v1.GetIngesterDefaultsRequest]) (*connect.Response[v1.GetIngesterDefaultsResponse], error)
	// TriggerIngester sends a one-shot trigger to a running ingester.
	// Only supported by ingesters that implement the Triggerable interface (e.g. scatterbox).
	TriggerIngester(context.Context, *connect.Request[v1.TriggerIngesterRequest]) (*connect.Response[v1.TriggerIngesterResponse], error)
	// PutNodeConfig creates or updates a node configuration.
	PutNodeConfig(context.Context, *connect.Request[v1.PutNodeConfigRequest]) (*connect.Response[v1.PutNodeConfigResponse], error)
	// PutRoute creates or updates a route.
	PutRoute(context.Context, *connect.Request[v1.PutRouteRequest]) (*connect.Response[v1.PutRouteResponse], error)
	// DeleteRoute removes a route.
	DeleteRoute(context.Context, *connect.Request[v1.DeleteRouteRequest]) (*connect.Response[v1.DeleteRouteResponse], error)
	// GenerateName returns a random petname for use as a default entity name.
	GenerateName(context.Context, *connect.Request[v1.GenerateNameRequest]) (*connect.Response[v1.GenerateNameResponse], error)
	// WatchConfig streams a notification whenever configuration changes.
	WatchSystem(context.Context, *connect.Request[v1.WatchSystemRequest], *connect.ServerStream[v1.WatchSystemResponse]) error
	// GetRouteStats returns live routing statistics.
	GetRouteStats(context.Context, *connect.Request[v1.GetRouteStatsRequest]) (*connect.Response[v1.GetRouteStatsResponse], error)
	// ListManagedFiles returns all managed files.
	ListManagedFiles(context.Context, *connect.Request[v1.ListManagedFilesRequest]) (*connect.Response[v1.ListManagedFilesResponse], error)
	// DeleteManagedFile removes an managed file.
	DeleteManagedFile(context.Context, *connect.Request[v1.DeleteManagedFileRequest]) (*connect.Response[v1.DeleteManagedFileResponse], error)
	// TestCloudService tests connectivity for a cloud storage configuration without saving it.
	TestCloudService(context.Context, *connect.Request[v1.TestCloudServiceRequest]) (*connect.Response[v1.TestCloudServiceResponse], error)
	// TestHTTPLookup tests an HTTP lookup configuration with a sample value.
	TestHTTPLookup(context.Context, *connect.Request[v1.TestHTTPLookupRequest]) (*connect.Response[v1.TestHTTPLookupResponse], error)
	// PreviewCSVLookup reads a managed CSV file and returns column headers, sample rows, and total row count.
	PreviewCSVLookup(context.Context, *connect.Request[v1.PreviewCSVLookupRequest]) (*connect.Response[v1.PreviewCSVLookupResponse], error)
	// PreviewJSONLookup reads a managed JSON file and returns pretty-printed content for structure inspection.
	PreviewJSONLookup(context.Context, *connect.Request[v1.PreviewJSONLookupRequest]) (*connect.Response[v1.PreviewJSONLookupResponse], error)
	// PreviewYAMLLookup reads a managed YAML file and returns pretty-printed content for structure inspection.
	PreviewYAMLLookup(context.Context, *connect.Request[v1.PreviewYAMLLookupRequest]) (*connect.Response[v1.PreviewYAMLLookupResponse], error)
	// WatchIngesterStatus streams a single ingester's status whenever underlying state changes
	// (config edits, alive-state transitions, or broadcast stats updates). Event-driven replacement
	// for polling GetIngesterStatus. Initial snapshot sent on subscribe.
	WatchIngesterStatus(context.Context, *connect.Request[v1.WatchIngesterStatusRequest], *connect.ServerStream[v1.WatchIngesterStatusResponse]) error
	// Cloud services
	PutCloudService(context.Context, *connect.Request[v1.PutCloudServiceRequest]) (*connect.Response[v1.PutCloudServiceResponse], error)
	DeleteCloudService(context.Context, *connect.Request[v1.DeleteCloudServiceRequest]) (*connect.Response[v1.DeleteCloudServiceResponse], error)
	// Node storage
	SetNodeStorageConfig(context.Context, *connect.Request[v1.SetNodeStorageConfigRequest]) (*connect.Response[v1.SetNodeStorageConfigResponse], error)
	// Tiers
	PutTier(context.Context, *connect.Request[v1.PutTierRequest]) (*connect.Response[v1.PutTierResponse], error)
	DeleteTier(context.Context, *connect.Request[v1.DeleteTierRequest]) (*connect.Response[v1.DeleteTierResponse], error)
	// DeleteLookup removes a lookup table by name (any type).
	DeleteLookup(context.Context, *connect.Request[v1.DeleteLookupRequest]) (*connect.Response[v1.DeleteLookupResponse], error)
	// GetLogLevels returns the current per-component log levels for this
	// node, plus the default level for components without an explicit
	// setting. See gastrolog-3flfp.
	GetLogLevels(context.Context, *connect.Request[v1.GetLogLevelsRequest]) (*connect.Response[v1.GetLogLevelsResponse], error)
	// SetLogLevel sets the minimum log level for a component on this node
	// at runtime — no restart needed. The change is local to the node that
	// serves the RPC; operators wanting cluster-wide changes apply per-node.
	// Empty component_name targets the default level. See gastrolog-3flfp.
	SetLogLevel(context.Context, *connect.Request[v1.SetLogLevelRequest]) (*connect.Response[v1.SetLogLevelResponse], error)
	// ClearLogLevel removes the per-component override, reverting that
	// component to the default level. No-op if no override is set.
	// See gastrolog-3flfp.
	ClearLogLevel(context.Context, *connect.Request[v1.ClearLogLevelRequest]) (*connect.Response[v1.ClearLogLevelResponse], error)
}

